interface.definition:
a!localVariables(
  local!healthAppointment: #"SYSTEM_SYSRULES_queryRecordByIdentifier"(
    recordType: #"urn:appian:record-type:v1:1b96054c-af55-4d2a-a907-daf8f6cb05ed",
    identifier: ri!healthAppointmentId,
  ),
  local!healthService: #"SYSTEM_SYSRULES_queryRecordByIdentifier"(
    recordType: #"urn:appian:record-type:v1:bee451d4-0dcb-4706-b938-9a1084b98ff7",
    identifier: local!healthAppointment[#"urn:appian:record-field:v1:1b96054c-af55-4d2a-a907-daf8f6cb05ed/90123e83-5fd9-46fe-86ba-fa35973f05b0"]
  ),
  local!helathServiceCategory: #"SYSTEM_SYSRULES_queryRecordByIdentifier"(
    recordType: #"urn:appian:record-type:v1:171b5794-c97f-4c2c-b7f6-af1701ceff62",
    identifier: local!healthService[#"urn:appian:record-field:v1:bee451d4-0dcb-4706-b938-9a1084b98ff7/fc9e8002-ba9b-4d1f-a6be-a3d59ae8c622"]
  ),
  #"SYSTEM_SYSRULES_formLayout_v1"(
    label: local!healthService[#"urn:appian:record-field:v1:bee451d4-0dcb-4706-b938-9a1084b98ff7/3395909e-62bd-48c8-97e0-478127566586"] & " (" & local!helathServiceCategory[#"urn:appian:record-field:v1:171b5794-c97f-4c2c-b7f6-af1701ceff62/5a0b9e22-6384-436e-98e1-4adb8dcebe72"] & ")",
    contents: {
      #"SYSTEM_SYSRULES_columnsLayout"(
        columns: {
          #"SYSTEM_SYSRULES_columnLayout"(
            contents: {
              #"SYSTEM_SYSRULES_richTextDisplayField"(
                label: "Datum und Uhrzeit",
                value: #"SYSTEM_SYSRULES_richTextItem_v1"(
                  text: datetext(local!healthAppointment[#"urn:appian:record-field:v1:1b96054c-af55-4d2a-a907-daf8f6cb05ed/88976b74-9849-4755-ba2d-84be6b211239"],"EEE dd. MMM YYYY")
                )
              ),
              #"SYSTEM_SYSRULES_richTextDisplayField"(
                label: "Externer Termin",
                value: #"SYSTEM_SYSRULES_richTextItem_v1"(
                  text: a!match(
                    value: local!healthAppointment[#"urn:appian:record-field:v1:1b96054c-af55-4d2a-a907-daf8f6cb05ed/933f01c7-e510-476f-a578-80dc87560e6c"],
                    equals: true,
                    then: "Ja",
                    equals: false,
                    then: "Nein",
                    default: "Nein"
                  )
                )
              )
            }
          ),
          #"SYSTEM_SYSRULES_columnLayout"(
            contents: {
              #"SYSTEM_SYSRULES_richTextDisplayField"(
                label: "Information zum Termin",
                value: #"SYSTEM_SYSRULES_richTextItem_v1"(
                  text: {
                    local!healthService[#"urn:appian:record-field:v1:bee451d4-0dcb-4706-b938-9a1084b98ff7/fb111408-d2a3-4902-bd51-bf8fff8ffda6"],
                    char(10),
                    local!healthAppointment[#"urn:appian:record-field:v1:1b96054c-af55-4d2a-a907-daf8f6cb05ed/8735947f-5864-4fdf-a9d8-09b8847bd9b7"]
                  }
                )
              )
            }
          )
        }
      ),
      #"SYSTEM_SYSRULES_styledTextEditorField"(
        label: "Zusätzliche Informationen",
        instructions: "Bitte geben sie die zusätzlichen Informationen zum Termin ein",
        sizeLimit: 1000,
        showWhen: local!healthAppointment[#"urn:appian:record-field:v1:1b96054c-af55-4d2a-a907-daf8f6cb05ed/dc1a9af4-55a0-46ed-aef1-f8e0b5710d18"],
        value: local!healthAppointment[#"urn:appian:record-field:v1:1b96054c-af55-4d2a-a907-daf8f6cb05ed/dd48644c-94f4-45be-b9b9-3a8933075d8c"],
        saveInto: local!healthAppointment[#"urn:appian:record-field:v1:1b96054c-af55-4d2a-a907-daf8f6cb05ed/dd48644c-94f4-45be-b9b9-3a8933075d8c"]
      )
    },
    buttons: #"SYSTEM_SYSRULES_ButtonLayout"(
      secondaryButtons: {
        #"SYSTEM_SYSRULES_buttonWidget_v1"(
          label: "Schließen",
          saveInto: a!save(ri!cancel,true),
          submit: true,
          validate: false
        )
      },
      primaryButtons: {
        #"SYSTEM_SYSRULES_buttonWidget_v1"(
          label: "Speichern",
          showWhen: local!healthAppointment[#"urn:appian:record-field:v1:1b96054c-af55-4d2a-a907-daf8f6cb05ed/dc1a9af4-55a0-46ed-aef1-f8e0b5710d18"],
          saveInto: {
            a!save(ri!cancel,false),
            a!save(ri!healthAppointment,local!healthAppointment)
          }
        )
      }
    )
  )
)
